import React from 'react';

type Status = 'idle' | 'loading' | 'success' | 'error';

interface StatusPanelProps {
  status: Status;
  errorMessage?: string;
  retryCount?: number;
}

function StatusPanel({ status, errorMessage, retryCount = 0 }: StatusPanelProps): JSX.Element {
  let content: React.ReactNode;

  switch (status) {
    case 'loading':
      content = 'Loading...';
      break;
    case 'success':
      content = 'Done!';
      break;
    case 'error':
      content = errorMessage || 'Something went wrong';
      break;
    case 'idle':
    default:
      content = 'Ready to start';
      break;
  }

  return (
    <div>
      <p>{content}</p>
      {retryCount > 0 && <span className="badge">Retries: {retryCount}</span>}
    </div>
  );
}

export default StatusPanel;

