import React, { useState, useCallback } from 'react';

function useToggle(initialValue: boolean = false): [boolean, () => void, (value: boolean) => void] {
  const [value, setValue] = useState(initialValue);

  const toggle = useCallback(() => {
    setValue((prev) => !prev);
  }, []);

  return [value, toggle, setValue];
}

function Sidebar(): JSX.Element {
  const [isOpen, toggleOpen] = useToggle(false);

  return (
    <div>
      <button onClick={toggleOpen}>{isOpen ? 'Close' : 'Open'} Sidebar</button>
      {isOpen && <nav>Sidebar content</nav>}
    </div>
  );
}

function Modal(): JSX.Element {
  const [isVisible, toggleVisible, setVisible] = useToggle(false);

  return (
    <div>
      <button onClick={toggleVisible}>Toggle Modal</button>
      {isVisible && (
        <div className="modal">
          Modal content
          <button onClick={() => setVisible(false)}>Close</button>
        </div>
      )}
    </div>
  );
}

export { useToggle, Sidebar, Modal };

