function useLocalStorage<T>(
  key: string,
  initialValue: T
): [T, (value: T | ((prev: T) => T)) => void] {
  // 1. Guard every localStorage access behind `typeof window !== 'undefined'`
  // 2. Lazy-initialize state by reading from localStorage (or initialValue if SSR / missing / bad JSON)
  // 3. setValue: resolve functional updaters against the current state, then
  //    update React state AND write to localStorage (wrapped in try/catch)
  // 4. useEffect: subscribe to the native 'storage' event; when event.key === key,
  //    parse event.newValue (or fall back to initialValue if newValue is null) and update state
  // 5. Clean up the event listener on unmount

  return [initialValue, () => {}]; // replace with real implementation
}

solution:
function useLocalStorage<T>(
  key: string,
  initialValue: T
): [T, (value: T | ((prev: T) => T)) => void] {
  const readValue = useCallback((): T => {
    if (typeof window === 'undefined') return initialValue;
    try {
      const item = window.localStorage.getItem(key);
      return item !== null ? (JSON.parse(item) as T) : initialValue;
    } catch {
      return initialValue;
    }
  }, [key, initialValue]);

  const [storedValue, setStoredValue] = useState<T>(readValue);

  const setValue = useCallback(
    (value: T | ((prev: T) => T)) => {
      setStoredValue((prev) => {
        const nextValue = value instanceof Function ? value(prev) : value;
        if (typeof window !== 'undefined') {
          try {
            window.localStorage.setItem(key, JSON.stringify(nextValue));
          } catch {
            // quota exceeded or storage unavailable -- keep React state in sync anyway
          }
        }
        return nextValue;
      });
    },
    [key]
  );

  useEffect(() => {
    if (typeof window === 'undefined') return;

    function handleStorageChange(event: StorageEvent) {
      if (event.key !== key) return;
      try {
        setStoredValue(event.newValue !== null ? (JSON.parse(event.newValue) as T) : initialValue);
      } catch {
        setStoredValue(initialValue);
      }
    }

    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, [key, initialValue]);

  return [storedValue, setValue];
}

