function useFetch<T>(url: string | null, options: { retries?: number } = {}): UseFetchResult<T> {
  // 1. State: data, error, loading
  // 2. useEffect depends on [url, options.retries]:
  //    - if url is null, reset data/error/loading and return early (no cleanup needed)
  //    - create an AbortController for this effect run
  //    - define an async function that fetches, and on failure retries up to `retries`
  //      times (skip incrementing/erroring if the error is an AbortError)
  //    - call it, updating loading/data/error appropriately
  // 3. Return the AbortController's abort() as the cleanup function

  return { data: null, error: null, loading: false }; // replace with real implementation
}

solution:
interface UseFetchResult<T> {
  data: T | null;
  error: Error | null;
  loading: boolean;
}

function useFetch<T>(url: string | null, options: { retries?: number } = {}): UseFetchResult<T> {
  const { retries = 0 } = options;
  const [state, setState] = useState<UseFetchResult<T>>({ data: null, error: null, loading: false });

  useEffect(() => {
    if (url === null) {
      setState({ data: null, error: null, loading: false });
      return;
    }

    const controller = new AbortController();
    let attemptsLeft = retries;

    async function attemptFetch(): Promise<void> {
      setState((prev) => ({ ...prev, loading: true, error: null }));
      try {
        const response = await fetch(url as string, { signal: controller.signal });
        if (!response.ok) {
          throw new Error(`Request failed with status ${response.status}`);
        }
        const json = (await response.json()) as T;
        setState({ data: json, error: null, loading: false });
      } catch (err) {
        if ((err as Error).name === 'AbortError') {
          return; // superseded request, discard silently
        }
        if (attemptsLeft > 0) {
          attemptsLeft -= 1;
          await attemptFetch();
          return;
        }
        setState({ data: null, error: err as Error, loading: false });
      }
    }

    attemptFetch();

    return () => controller.abort();
  }, [url, retries]);

  return state;
}

