import React, { ReactNode, useState, useCallback, createContext, useContext } from 'react';

interface AccordionContextType {
  value: string | string[];
  onValueChange: (value: string | string[]) => void;
  type: 'single' | 'multiple';
  collapsible: boolean;
}

const AccordionContext = createContext<AccordionContextType | undefined>(undefined);

function useAccordionContext() {
  const context = useContext(AccordionContext);
  if (!context) {
    throw new Error('Accordion components must be used within Accordion');
  }
  return context;
}

interface AccordionProps {
  children: ReactNode;
  type?: 'single' | 'multiple';
  value?: string | string[];
  onValueChange?: (value: string | string[]) => void;
  collapsible?: boolean;
  defaultValue?: string | string[];
}

function Accordion({ children, type = 'single', value: controlledValue, onValueChange, collapsible = false, defaultValue = type === 'single' ? '' : [] }: AccordionProps) {
  const [uncontrolledValue, setUncontrolledValue] = useState<string | string[]>(defaultValue);
  const isControlled = controlledValue !== undefined;
  const value = isControlled ? controlledValue : uncontrolledValue;

  const handleValueChange = useCallback((newValue: string | string[]) => {
    if (!isControlled) {
      setUncontrolledValue(newValue);
    }
    onValueChange?.(newValue);
  }, [isControlled, onValueChange]);

  const contextValue: AccordionContextType = {
    value,
    onValueChange: handleValueChange,
    type,
    collapsible
  };

  return (
    <AccordionContext.Provider value={contextValue}>
      <div role="region" className="accordion">
        {children}
      </div>
    </AccordionContext.Provider>
  );
}

interface ItemProps {
  children: ReactNode;
  value: string;
  disabled?: boolean;
}

function Item({ children, value: itemValue, disabled = false }: ItemProps) {
  const context = useAccordionContext();
  const isOpen = context.type === 'single' 
    ? context.value === itemValue 
    : Array.isArray(context.value) && context.value.includes(itemValue);

  return (
    <div className="accordion-item" data-state={isOpen ? 'open' : 'closed'} data-disabled={disabled}>
      <AccordionContext.Provider value={{ ...context }}
      >
        {React.Children.map(children, (child) =>
          React.isValidElement(child)
            ? React.cloneElement(child as React.ReactElement<any>, { itemValue, isOpen, disabled })
            : child
        )}
      </AccordionContext.Provider>
    </div>
  );
}

interface HeaderProps {
  children: ReactNode;
  itemValue?: string;
  isOpen?: boolean;
  disabled?: boolean;
}

function Header({ children, itemValue, isOpen = false, disabled = false }: HeaderProps) {
  const context = useAccordionContext();

  const handleClick = useCallback(() => {
    if (disabled || !itemValue) return;

    if (context.type === 'single') {
      if (isOpen && context.collapsible) {
        context.onValueChange('');
      } else {
        context.onValueChange(itemValue);
      }
    } else {
      const newValue = Array.isArray(context.value) ? [...context.value] : [];
      const index = newValue.indexOf(itemValue);
      if (index > -1) {
        newValue.splice(index, 1);
      } else {
        newValue.push(itemValue);
      }
      context.onValueChange(newValue);
    }
  }, [context, itemValue, isOpen, disabled]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (disabled) return;
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      handleClick();
    }
  };

  return (
    <button
      className="accordion-header"
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      aria-expanded={isOpen}
      disabled={disabled}
      data-state={isOpen ? 'open' : 'closed'}
    >
      {children}
    </button>
  );
}

interface PanelProps {
  children: ReactNode;
  isOpen?: boolean;
}

function Panel({ children, isOpen = false }: PanelProps) {
  return (
    <div
      className="accordion-panel"
      hidden={!isOpen}
      data-state={isOpen ? 'open' : 'closed'}
      role="region"
    >
      {children}
    </div>
  );
}

Accordion.Item = Item;
Accordion.Header = Header;
Accordion.Panel = Panel;

description.en:
You have an existing render props pattern component (DataFetcher) that needs migration to a custom hook. Requirements:

**Original Render Props Implementation:**
tsx
<DataFetcher url="/api/users">
  {(data, loading, error, refetch) => (
    <div>
      {loading && <p>Loading...</p>}
      {error && <p>Error: {error}</p>}
      {data && <UserList users={data} />}
      <button onClick={refetch}>Refresh</button>
    </div>
  )}
</DataFetcher>


**Requirements for Hook Version:**
1. Create `useFetch` hook that maintains same API
2. **Prevent unnecessary re-renders** - Child components shouldn't re-render on every state update
3. **Memoize returned values** - Use useMemo to prevent reference changes
4. **Handle abort on unmount** - Cancel in-flight requests when component unmounts
5. **Error boundaries support** - Propagate errors properly
6. **Parallel requests** - Support multiple concurrent fetches
7. **Cache management** - Optional caching layer to prevent duplicate requests

**Example Hook Usage:**
tsx
function UserListPage() {
  const { data, loading, error, refetch } = useFetch('/api/users');

  return (
    <div>
      {loading && <p>Loading...</p>}
      {error && <p>Error: {error}</p>}
      {data && <UserList users={data} />}
      <button onClick={refetch}>Refresh</button>
    </div>
  );
}


**Edge cases:**
- Rapid remount/unmount cycles
- URL/options changes during fetch
- Race conditions with multiple fetches
- Memory leaks from AbortController
- Stale closure issues

