import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';

interface FetchState<T> {
  data: T | null;
  loading: boolean;
  error: Error | null;
}

interface UseFetchOptions {
  headers?: Record<string, string>;
  method?: 'GET' | 'POST' | 'PUT' | 'DELETE';
  body?: any;
  cache?: boolean;
}

const globalCache = new Map<string, { data: any; timestamp: number }>();
const CACHE_DURATION = 5 * 60 * 1000; // 5 minutes

function useFetch<T = any>(url: string, options?: UseFetchOptions) {
  const [state, setState] = useState<FetchState<T>>({
    data: null,
    loading: true,
    error: null
  });

  const abortControllerRef = useRef<AbortController | null>(null);
  const isMountedRef = useRef(true);
  const urlRef = useRef(url);
  const optionsRef = useRef(options);

  const getCacheKey = useCallback(() => {
    return `${url}_${JSON.stringify(options || {})}`;
  }, [url, options]);

  const getCachedData = useCallback(() => {
    if (!options?.cache) return null;

    const cacheKey = getCacheKey();
    const cached = globalCache.get(cacheKey);

    if (cached && Date.now() - cached.timestamp < CACHE_DURATION) {
      return cached.data;
    }

    if (cached) {
      globalCache.delete(cacheKey);
    }

    return null;
  }, [getCacheKey, options?.cache]);

  const setCachedData = useCallback((data: T) => {
    if (!options?.cache) return;

    const cacheKey = getCacheKey();
    globalCache.set(cacheKey, {
      data,
      timestamp: Date.now()
    });
  }, [getCacheKey, options?.cache]);

  const refetch = useCallback(async () => {
    // Cancel previous request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    try {
      setState(prev => ({ ...prev, loading: true, error: null }));

      const cachedData = getCachedData();
      if (cachedData) {
        if (isMountedRef.current) {
          setState({
            data: cachedData,
            loading: false,
            error: null
          });
        }
        return;
      }

      const fetchOptions: RequestInit = {
        signal,
        headers: {
          'Content-Type': 'application/json',
          ...(options?.headers || {})
        },
        method: options?.method || 'GET'
      };

      if (options?.body) {
        fetchOptions.body = JSON.stringify(options.body);
      }

      const response = await fetch(url, fetchOptions);

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const data: T = await response.json();

      if (!isMountedRef.current) return;

      setCachedData(data);

      setState({
        data,
        loading: false,
        error: null
      });
    } catch (error) {
      if (error instanceof DOMException && error.name === 'AbortError') {
        // Request was cancelled, don't update state
        return;
      }

      if (isMountedRef.current) {
        setState({
          data: null,
          loading: false,
          error: error instanceof Error ? error : new Error(String(error))
        });
      }
    }
  }, [url, options, getCachedData, setCachedData]);

  useEffect(() => {
    isMountedRef.current = true;
    refetch();

    return () => {
      isMountedRef.current = false;
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, [url, refetch]);

  // Return memoized values to prevent unnecessary re-renders of consumers
  return useMemo(() => ({
    data: state.data,
    loading: state.loading,
    error: state.error,
    refetch
  }), [state.data, state.loading, state.error, refetch]);
}

export default useFetch;

description.en:
Implement a windowed/virtualized list component that renders only the DOM nodes currently visible (plus a small overscan buffer) instead of all items — the technique behind libraries like `react-window`, needed to keep 10,000+ row lists smooth.

**Requirements:**
- Accept `items: T[]`, a fixed `itemHeight` (px), a `containerHeight` (px), and a `renderItem: (item: T, index: number) => ReactNode`
- Render a scrollable container of `containerHeight` with an inner spacer sized to the *full* virtual content height (`items.length * itemHeight`), so the scrollbar reflects the true list size
- Only mount DOM nodes for items currently within the visible viewport, positioned absolutely (or via transform) at their correct offset
- Include an `overscan` count (default 3) of extra items rendered above and below the visible range, to reduce blank flashes during fast scrolling
- Recompute the visible range on scroll, driven by `scrollTop`, without re-rendering on every single pixel of scroll (throttle/batch appropriately)
- Must handle `items` changing length (e.g. filtering shrinks the list) without leaving stale rendered nodes or an incorrect spacer height

**Function signature:**
```typescript
interface VirtualizedListProps<T> {
  items: T[];
  itemHeight: number;
  containerHeight: number;
  overscan?: number;
  renderItem: (item: T, index: number) => React.ReactNode;
}

function VirtualizedList<T>(props: VirtualizedListProps<T>): JSX.Element
```

**Example:**
```tsx
<VirtualizedList
  items={tenThousandRows}
  itemHeight={40}
  containerHeight={600}
  renderItem={(row, i) => <Row key={row.id} data={row} />}
/>
// only ~18-20 DOM nodes exist at any time (600/40 visible + overscan), not 10,000
```

**Edge cases:**
- `items` is empty
- Scrolling to the very bottom (last item must be fully reachable, not cut off by rounding)
- `itemHeight` doesn't evenly divide `containerHeight`
- Extremely fast scroll (e.g. dragging the scrollbar thumb) skipping many rows at once between scroll events

description.ru:
Реализуйте оконный/виртуализированный компонент списка, который рендерит только те DOM-узлы, что сейчас видимы (плюс небольшой буфер overscan), вместо всех элементов — техника, лежащая в основе библиотек вроде `react-window`, нужная, чтобы списки на 10000+ строк оставались плавными.

**Требования:**
- Принимает `items: T[]`, фиксированную `itemHeight` (px), `containerHeight` (px) и `renderItem: (item: T, index: number) => ReactNode`
- Рендерит скроллящийся контейнер высотой `containerHeight` с внутренним спейсером, размер которого равен *полной* виртуальной высоте контента (`items.length * itemHeight`), чтобы скроллбар отражал реальный размер списка
- Монтирует DOM-узлы только для элементов, находящихся сейчас в видимом viewport, позиционируя их абсолютно (или через transform) на корректном смещении
- Включает счётчик `overscan` (по умолчанию 3) дополнительных элементов, рендерящихся выше и ниже видимого диапазона, чтобы уменьшить мигание пустоты при быстром скролле
- Пересчитывает видимый диапазон при скролле, основываясь на `scrollTop`, без ре-рендера на каждый отдельный пиксель скролла (соответствующая throttle/батчинг)
- Должен обрабатывать изменение длины `items` (например, фильтрация уменьшила список) без устаревших отрендеренных узлов или некорректной высоты спейсера

**Сигнатура функции:**
```typescript
interface VirtualizedListProps<T> {
  items: T[];
  itemHeight: number;
  containerHeight: number;
  overscan?: number;
  renderItem: (item: T, index: number) => React.ReactNode;
}

function VirtualizedList<T>(props: VirtualizedListProps<T>): JSX.Element
```

**Пример:**
```tsx
<VirtualizedList
  items={tenThousandRows}
  itemHeight={40}
  containerHeight={600}
  renderItem={(row, i) => <Row key={row.id} data={row} />}
/>
// в любой момент существует лишь ~18-20 DOM-узлов (600/40 видимых + overscan), а не 10000
```

**Граничные случаи:**
- `items` пуст
- Скролл в самый низ (последний элемент должен быть полностью достижим, не обрезан из-за округления)
- `itemHeight` не делит `containerHeight` нацело
- Очень быстрый скролл (например, перетаскивание ползунка скроллбара), пропускающий много строк между событиями скролла

