solution:
interface UseUndoRedoResult<T> {
  value: T;
  set: (newValue: T) => void;
  undo: () => void;
  redo: () => void;
  canUndo: boolean;
  canRedo: boolean;
}

interface HistoryState<T> {
  history: T[];
  pointer: number;
}

function useUndoRedo<T>(initialValue: T, limit?: number): UseUndoRedoResult<T> {
  const [state, setState] = useState<HistoryState<T>>({
    history: [initialValue],
    pointer: 0,
  });

  const set = useCallback((newValue: T) => {
    setState((prev) => {
      if (newValue === prev.history[prev.pointer]) {
        return prev; // no-op on reference-equal value
      }

      const truncated = prev.history.slice(0, prev.pointer + 1);
      let nextHistory = [...truncated, newValue];
      let nextPointer = nextHistory.length - 1;

      if (limit && nextHistory.length > limit) {
        const overflow = nextHistory.length - limit;
        nextHistory = nextHistory.slice(overflow);
        nextPointer -= overflow;
      }

      return { history: nextHistory, pointer: nextPointer };
    });
  }, [limit]);

  const undo = useCallback(() => {
    setState((prev) => ({
      ...prev,
      pointer: Math.max(0, prev.pointer - 1),
    }));
  }, []);

  const redo = useCallback(() => {
    setState((prev) => ({
      ...prev,
      pointer: Math.min(prev.history.length - 1, prev.pointer + 1),
    }));
  }, []);

  return {
    value: state.history[state.pointer],
    set,
    undo,
    redo,
    canUndo: state.pointer > 0,
    canRedo: state.pointer < state.history.length - 1,
  };
}
